      
import subprocess
import sys
import os
import threading
import re

def _analyze_and_append_smart_feedback(log_file_path, cwd):
    """
    INTERNAL HELPER: Reads the log file, looks for FileNotFoundError,
    performs Ancestor Search, and appends the smart hint back to the log file.
    """
    try:
        # 1. Read the error log generated by the failed process
        if not os.path.exists(log_file_path):
            return

        with open(log_file_path, 'r', encoding='utf-8', errors='replace') as f:
            log_content = f.read()

        # 2. Regex to capture the missing path from standard Python tracebacks
        # Matches: FileNotFoundError: [Errno 2] No such file or directory: 'WRONG_PATH'
        # Also handles single or double quotes
        match = re.search(r"FileNotFoundError:.*?['\"](.*?)['\"]", log_content)
        
        if match:
            bad_path_str = match.group(1)
            
            # Resolve relative paths relative to the CWD where the command ran
            if not os.path.isabs(bad_path_str):
                # Construct absolute path for checking, but show relative in output
                check_path = os.path.join(cwd, bad_path_str)
            else:
                check_path = bad_path_str

            # 3. Recursive Ancestor Search (The Smart Logic)
            current_dir = os.path.dirname(check_path)
            
            # Walk up until we find a directory that actually exists
            while current_dir and not os.path.exists(current_dir):
                parent = os.path.dirname(current_dir)
                if parent == current_dir: # Reached filesystem root
                    break 
                current_dir = parent

            # 4. Generate the Feedback Message
            feedback_msg = ""
            if current_dir and os.path.exists(current_dir):
                try:
                    contents = os.listdir(current_dir)
                    # Limit to 20 files to keep context clean
                    content_preview = str(contents[:20]) + ("..." if len(contents) > 20 else "")
                    
                    feedback_msg = (
                        f"\n\n[BENCHMARK SYSTEM HINT]\n"
                        f"Detected FileNotFoundError for: '{bad_path_str}'\n"
                        # f"DEBUG INFO: The directory '{os.path.dirname(bad_path_str)}' was not found.\n"
                        f"However, the nearest existing ancestor directory is: '{current_dir}'\n"
                        f"It contains these files/folders: {content_preview}\n"
                        f"-> ACTION: Please check for typos in the folder name or path structure.\n"
                    )
                except Exception as e:
                    pass # Permission error or other OS issue
            
            # 5. Append this hint to the log file so the Agent sees it
            if feedback_msg:
                print(f"  [Smart Feedback] Appending path hints to {log_file_path}...")
                with open(log_file_path, 'a', encoding='utf-8') as f:
                    f.write(feedback_msg)

    except Exception as e:
        print(f"  [Smart Feedback Error] Failed to analyze logs: {e}")


def run_command_streaming(command, cwd, log_file_path, timeout=None):
    """
    Executes a command, streams output, and appends smart debugging hints if it fails.
    """
    print(f"  [Exec] Streaming output to console and {log_file_path}...")
    
    # Ensure log directory exists
    log_dir = os.path.dirname(log_file_path)
    if log_dir and not os.path.exists(log_dir):
        os.makedirs(log_dir)

    # 准备日志文件
    f_log = open(log_file_path, 'w', encoding='utf-8')
    
    process = subprocess.Popen(
        command,
        cwd=cwd,
        shell=True,
        stdout=subprocess.PIPE,     
        stderr=subprocess.STDOUT,   
        text=True,                  
        bufsize=1,                  
        encoding='utf-8',
        errors='replace'            
    )

    def stream_reader(proc, log_file):
        try:
            for line in proc.stdout:
                sys.stdout.write(line)
                log_file.write(line)
                log_file.flush()
        except Exception:
            pass

    t = threading.Thread(target=stream_reader, args=(process, f_log))
    t.daemon = True 
    t.start()
    
    result_code = -1
    status_msg = ""

    try:
        process.wait(timeout=timeout)
        result_code = process.returncode
        status_msg = "Finished" if result_code == 0 else "Failed"
        
    except subprocess.TimeoutExpired:
        print(f"\n  [Error] Process timed out after {timeout} seconds. Killing...")
        process.kill()
        result_code = -1
        status_msg = "TIMEOUT_EXPIRED"
        
    except Exception as e:
        print(f"\n  [Error] Exception during execution: {e}")
        process.kill()
        result_code = -1
        status_msg = str(e)
        
    finally:
        t.join(timeout=1.0)
        f_log.close()

        # === INTEGRATION POINT: SMART FEEDBACK ===
        # If the process failed (non-zero exit code), analyze the logs for path errors
        if result_code != 0:
            _analyze_and_append_smart_feedback(log_file_path, cwd)

    return result_code, status_msg

def code_development_env(llm_input, working_file_path, command, cwd_location, function_name, python_path=None, timeout=600):
    """
    Args:
        timeout: 超时时间（秒）。如果代码运行超过此时间将被强制终止。
    """
    
    # 构造执行命令
    if python_path:
        command = f"{python_path} test_{function_name}.py"
    else:
        command = f"python test_{function_name}.py"
        
    execution_log_path = os.path.join(cwd_location, f"execution_log_{function_name}.txt")
    
    # 写入代码文件
    with open(working_file_path, 'w', encoding='utf-8') as f:
        f.write(llm_input)

    # run_command_streaming 已经支持 timeout，这里传入即可
    # 注意：这里接收 status_msg 以便后续判断是否超时
    return_code, status_msg = run_command_streaming(
        command,
        cwd=cwd_location,
        log_file_path=execution_log_path,
        timeout=timeout  # <--- 关键修改：传入超时时间
    )

    # 读取日志内容用于分析
    test_output_content = ""
    if os.path.exists(execution_log_path):
        with open(execution_log_path, 'r', encoding='utf-8', errors='ignore') as f:
            test_output_content = f.read()

    # --- 结果判定逻辑 ---
    if return_code == 0:
        results = {"status": "SUCCESS", "error": None}
    else:
        # 优先检查是否是超时导致的错误
        if status_msg == "TIMEOUT_EXPIRED":
            error_msg = f"TimeoutError: Execution exceeded {timeout} seconds and was terminated."
            print(f"  [Result] {error_msg}")
            
            # 也可以把部分已输出的日志附加上去
            max_chars = 1000
            log_tail = test_output_content[-max_chars:] if len(test_output_content) > max_chars else test_output_content
            full_error = f"{error_msg}\n\nLast Output:\n{log_tail}"
            
            results = {"status": "FAIL", "error": full_error}
            
        elif "TEST WRONG ANSWER" in test_output_content:
            print("test_output_content", test_output_content)
            print("wrong answer")
            results = {"status": "Wronganswer", "error": None}
            
        else:
            print("test_output_content", test_output_content)
            max_chars = 2000
            error_tail = test_output_content[-max_chars:] if len(test_output_content) > max_chars else test_output_content
            
            print(f"Error Tail: {error_tail[-200:]}...")
            results = {"status": "FAIL", "error": error_tail}

    # 清理工作文件（根据你之前的逻辑保留）
    # with open(working_file_path, 'w', encoding='utf-8') as f:
    #    f.write('')
    
    return results, llm_input
    